(function () {
    var box = document.querySelector('[data-search-box]');
    var result = document.querySelector('[data-search-results]');
    if (!box || !result || !window.SEARCH_INDEX) {
        return;
    }

    var params = new URLSearchParams(window.location.search);
    var first = params.get('q') || '';
    box.value = first;

    function safe(value) {
        return String(value || '').replace(/[&<>"]/g, function (char) {
            return {
                '&': '&amp;',
                '<': '&lt;',
                '>': '&gt;',
                '"': '&quot;'
            }[char];
        });
    }

    function render() {
        var keyword = box.value.trim().toLowerCase();
        var list = window.SEARCH_INDEX.filter(function (item) {
            if (!keyword) {
                return true;
            }
            return [
                item.title,
                item.year,
                item.region,
                item.type,
                item.category,
                item.desc,
                (item.tags || []).join(' ')
            ].join(' ').toLowerCase().indexOf(keyword) !== -1;
        }).slice(0, 120);

        if (!list.length) {
            result.innerHTML = '<div class="empty-state">没有找到匹配内容</div>';
            return;
        }

        result.innerHTML = list.map(function (item) {
            return [
                '<article class="movie-card">',
                '<a href="' + safe(item.url) + '" class="card-link">',
                '<div class="poster-frame">',
                '<img src="' + safe(item.image) + '" alt="' + safe(item.title) + '" loading="lazy">',
                '<span class="duration">' + safe(item.duration) + '</span>',
                '<span class="category-badge">' + safe(item.category) + '</span>',
                '</div>',
                '<div class="card-body">',
                '<h3>' + safe(item.title) + '</h3>',
                '<p>' + safe(item.desc) + '</p>',
                '<div class="card-meta">',
                '<span>' + safe(item.year) + '</span>',
                '<span>' + safe(item.region) + '</span>',
                '<span>' + safe(item.type) + '</span>',
                '</div>',
                '</div>',
                '</a>',
                '</article>'
            ].join('');
        }).join('');
    }

    box.addEventListener('input', render);
    render();
})();
